1	export const runScenario = (_input: unknown): unknown => {
2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest case
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums per item type
15	  it.todo("single sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
19	
20	  // Components
21	  it.todo("single rune → premium 30 G (25 base + 5 fee)");
22	  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
23	
24	  // Block discount for 3 alike components
25	  it.todo("3 runes → premium 65 G (60 base via block + 5 fee)");
26	  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
27	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
28	
29	  // Alike means same type
30	  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block + 5 fee)");
31	  it.todo("3 runes + 3 moonstones → premium 125 G (120 base, two blocks + 5 fee)");
32	
33	  // First insurance surcharge (per item, +10%)
34	  it.todo("newcomer single sword (no previous contract) → first insurance applies to item; premium 115 G (100 + 10 + 5)");
35	
36	  // Cursed surcharge (+50% of item's base premium)
37	  it.todo("newcomer cursed sword (steel, enchantment 3) → premium 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");
38	
39	  // High enchantment surcharge (≥5 → +30%)
40	  it.todo("sword with enchantment 5 → high-enchantment surcharge applies (130 + 10 first + 5 = 145 G for newcomer)");
41	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 first + 5 = 115 G for newcomer)");
42	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
43	
44	  // Loyalty discount (≥2 years → -20% on policy base premium)
45	  it.todo("loyal customer (exactly 2 years) single sword → loyalty discount applies");
46	
47	  // Follow-up contract discount (-15% on policy base premium)
48	  it.todo("second quote for same customer → follow-up contract discount applies");
49	
50	  // Modifier scope on multi-item policies
51	  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword (210 G before fee)");
52	
53	  // Rounding in MHPCO's favor (premium rounded up)
54	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
55	
56	  // Integration examples
57	  it.todo("newcomer with cursed sword → premium 165 G");
58	  it.todo("long-standing customer's second contract with cursed sword enchantment 7 → premium 160 G");
59	
60	  // ---- Claim processing ----
61	
62	  // Standard reimbursement
63	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
64	  it.todo("rune damaged (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");
65	
66	  // High enchantment clause (≥8 → 50% reimbursement)
67	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
68	
69	  // Dragon material clause (full reimbursement)
70	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
71	
72	  // Both clauses → 50% rule wins
73	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G");
74	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G");
75	
76	  // Deductible per damage event
77	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");
78	
79	  // Multiple items of same type
80	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
81	  it.todo("dragon attack damages both swords (two damage entries) → each treated separately with own deductible");
82	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
83	
84	  // Cap exhaustion
85	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
86	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value, not modified premium)");
87	  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
88	  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 G, second 600 G");
89	
90	  // Rounding payout (down, in MHPCO's favor)
91	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
92	
93	  // Edge cases — errors
94	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results");
95	  it.todo("claim references damage with item not in policy → CLI exits non-zero");
96	  it.todo("claim damage with negative amount → CLI exits non-zero");
97	});
